custom_css:
/* Reduce banner height */
.page-header {
    height: 180px !important;
    min-height: 400px !important;
    overflow: hidden;
}

/* Make the image fit nicely */
.page-header img {
    width: 100%;
    height: 400px !important;
    object-fit: cover;
}

/* Remove extra spacing below banner */
.page-header-wrapper {
    margin-bottom: 10px !important;
}

client_script:
frappe.web_form.on('resume_link', (field, value) => {
    if (!frappe.utils.is_url(value)) {
        frappe.msgprint(__('Resume link not valid'));
    }
});

frappe.web_form.after_load = () => {
    if (window.location.pathname.endsWith("/new") && frappe.session.user) {
        let current_path = window.location.href;
        window.location.href = current_path.replace("/new", "/" + frappe.session.user);
    }
}
